import logging
import os
import hashlib
import secrets
from datetime import datetime, timedelta
from functools import wraps

from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# Configure logging - NOTE: We NEVER log passwords or sensitive credentials
log_formatter = logging.Formatter(
    '%(asctime)s - %(levelname)s - %(message)s'
)

file_handler = logging.FileHandler('application.log')
file_handler.setFormatter(log_formatter)
file_handler.setLevel(logging.INFO)

console_handler = logging.StreamHandler()
console_handler.setFormatter(log_formatter)
console_handler.setLevel(logging.DEBUG)

logger = logging.getLogger('auth_logger')
logger.setLevel(logging.DEBUG)
logger.addHandler(file_handler)
logger.addHandler(console_handler)

# In-memory user store (replace with a real database in production)
users_db = {}

# Rate limiting store
login_attempts = {}
MAX_ATTEMPTS = 5
LOCKOUT_DURATION = timedelta(minutes=15)


def get_client_ip():
    """Get the real client IP, considering proxies."""
    if request.headers.get('X-Forwarded-For'):
        return request.headers.get('X-Forwarded-For').split(',')[0].strip()
    return request.remote_addr


def mask_email(email):
    """Mask email for safe logging. user@example.com -> u***@example.com"""
    if not email or '@' not in email:
        return '***'
    local, domain = email.split('@', 1)
    if len(local) <= 1:
        masked_local = '*'
    else:
        masked_local = local[0] + '***'
    return f"{masked_local}@{domain}"


def mask_username(username):
    """Mask username for safe logging."""
    if not username:
        return '***'
    if len(username) <= 2:
        return username[0] + '*'
    return username[0] + '***' + username[-1]


def generate_request_id():
    """Generate a unique request ID for correlating log entries."""
    return secrets.token_hex(8)


def check_rate_limit(identifier):
    """Check if the identifier (IP or username) is rate-limited."""
    now = datetime.utcnow()
    if identifier in login_attempts:
        attempts, first_attempt_time = login_attempts[identifier]
        if now - first_attempt_time > LOCKOUT_DURATION:
            login_attempts[identifier] = (0, now)
            return True
        if attempts >= MAX_ATTEMPTS:
            return False
    return True


def record_attempt(identifier):
    """Record a failed login attempt."""
    now = datetime.utcnow()
    if identifier in login_attempts:
        attempts, first_attempt_time = login_attempts[identifier]
        if now - first_attempt_time > LOCKOUT_DURATION:
            login_attempts[identifier] = (1, now)
        else:
            login_attempts[identifier] = (attempts + 1, first_attempt_time)
    else:
        login_attempts[identifier] = (1, now)


def reset_attempts(identifier):
    """Reset login attempts after successful login."""
    if identifier in login_attempts:
        del login_attempts[identifier]


def log_auth_event(event_type, username, email=None, success=False, reason=None, request_id=None):
    """
    Securely log authentication events.
    
    SECURITY NOTE: We intentionally NEVER log passwords, tokens, or other secrets.
    Passwords are sensitive credentials - logging them would:
    1. Violate security best practices (OWASP)
    2. Risk credential exposure if logs are compromised
    3. Violate compliance requirements (GDPR, PCI-DSS, HIPAA, SOC2)
    4. Create legal liability
    """
    log_data = {
        'request_id': request_id or generate_request_id(),
        'event': event_type,
        'username_masked': mask_username(username),
        'email_masked': mask_email(email) if email else 'N/A',
        'ip_address': get_client_ip(),
        'user_agent': request.headers.get('User-Agent', 'Unknown'),
        'success': success,
        'reason': reason or 'N/A',
        'timestamp': datetime.utcnow().isoformat(),
        'method': request.method,
        'path': request.path,
    }

    log_message = (
        f"AUTH_EVENT | request_id={log_data['request_id']} | "
        f"event={log_data['event']} | "
        f"username={log_data['username_masked']} | "
        f"email={log_data['email_masked']} | "
        f"ip={log_data['ip_address']} | "
        f"user_agent={log_data['user_agent']} | "
        f"success={log_data['success']} | "
        f"reason={log_data['reason']}"
    )

    if success:
        logger.info(log_message)
    else:
        logger.warning(log_message)

    return log_data['request_id']


@app.route('/api/register', methods=['POST'])
def register():
    """Register a new user."""
    request_id = generate_request_id()
    data = request.get_json()

    if not data:
        logger.warning(f"REGISTER | request_id={request_id} | Invalid JSON payload from ip={get_client_ip()}")
        return jsonify({'error': 'Invalid JSON payload', 'request_id': request_id}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')
    email = data.get('email', '').strip()

    # Validation
    errors = []
    if not username or len(username) < 3:
        errors.append('Username must be at least 3 characters')
    if not password or len(password) < 8:
        errors.append('Password must be at least 8 characters')
    if not email or '@' not in email:
        errors.append('Valid email is required')

    if errors:
        log_auth_event('REGISTER_FAILED', username, email, 
                       success=False, reason='Validation failed', request_id=request_id)
        return jsonify({'error': 'Validation failed', 'details': errors, 'request_id': request_id}), 400

    if username.lower() in users_db:
        log_auth_event('REGISTER_FAILED', username, email,
                       success=False, reason='Username already exists', request_id=request_id)
        # Don't reveal that the username exists - use generic message
        return jsonify({'error': 'Registration failed. Please try different credentials.', 
                       'request_id': request_id}), 409

    # Store user with hashed password
    users_db[username.lower()] = {
        'username': username,
        'email': email,
        'password_hash': generate_password_hash(password),
        'created_at': datetime.utcnow().isoformat()
    }

    log_auth_event('REGISTER_SUCCESS', username, email, 
                   success=True, request_id=request_id)

    return jsonify({
        'message': 'User registered successfully',
        'request_id': request_id
    }), 201


@app.route('/api/login', methods=['POST'])
def login():
    """Authenticate a user."""
    request_id = generate_request_id()
    data = request.get_json()

    if not data:
        logger.warning(f"LOGIN | request_id={request_id} | Invalid JSON payload from ip={get_client_ip()}")
        return jsonify({'error': 'Invalid JSON payload', 'request_id': request_id}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        log_auth_event('LOGIN_FAILED', username,
                       success=False, reason='Missing credentials', request_id=request_id)
        return jsonify({'error': 'Username and password are required', 
                       'request_id': request_id}), 400

    # Check rate limiting
    client_ip = get_client_ip()
    ip_key = f"ip:{client_ip}"
    user_key = f"user:{username.lower()}"

    if not check_rate_limit(ip_key) or not check_rate_limit(user_key):
        log_auth_event('LOGIN_RATE_LIMITED', username,
                       success=False, reason='Too many failed attempts', request_id=request_id)
        logger.warning(
            f"RATE_LIMIT | request_id={request_id} | "
            f"username={mask_username(username)} | ip={client_ip} | "
            f"Too many login attempts - account temporarily locked"
        )
        return jsonify({
            'error': 'Too many failed login attempts. Please try again later.',
            'request_id': request_id
        }), 429

    # Look up user
    user = users_db.get(username.lower())

    if not user:
        # Use constant-time comparison to prevent timing attacks
        # Hash a dummy password to keep response time consistent
        generate_password_hash('dummy_password_for_timing')
        
        record_attempt(ip_key)
        record_attempt(user_key)
        
        log_auth_event('LOGIN_FAILED', username,
                       success=False, reason='Invalid credentials', request_id=request_id)
        
        # Generic error message - don't reveal if user exists
        return jsonify({
            'error': 'Invalid username or password',
            'request_id': request_id
        }), 401

    # Verify password
    if not check_password_hash(user['password_hash'], password):
        record_attempt(ip_key)
        record_attempt(user_key)

        log_auth_event('LOGIN_FAILED', username, user.get('email'),
                       success=False, reason='Invalid credentials', request_id=request_id)

        return jsonify({
            'error': 'Invalid username or password',
            'request_id': request_id
        }), 401

    # Successful login
    reset_attempts(ip_key)
    reset_attempts(user_key)

    # Generate a simple session token (use JWT or proper session management in production)
    session_token = secrets.token_urlsafe(32)

    log_auth_event('LOGIN_SUCCESS', username, user.get('email'),
                   success=True, request_id=request_id)

    return jsonify({
        'message': 'Login successful',
        'token': session_token,
        'username': user['username'],
        'request_id': request_id
    }), 200


